(function($){'use strict';function initSettingsMenu(){if(window.ghlSettingsMenuInitialized){return}
window.ghlSettingsMenuInitialized=!0;initMobileMenuToggle();const hash=window.location.hash.slice(1);if(hash&&hash!==''){const $tab=$('.ghl-settings-nav li[data-tab="'+hash+'"]');if($tab.length){loadSettingsTab(hash);$('.ghl-settings-nav li').removeClass('active');$tab.addClass('active')}}
$(document).off('click.ghlSettingsMenu','.ghl-settings-nav li');$(window).off('hashchange.ghlSettingsMenu');$(document).on('click.ghlSettingsMenu','.ghl-settings-nav li',function(e){e.preventDefault();const $tab=$(this);const tab=$tab.data('tab');if($tab.hasClass('active')){closeMobileMenu();return}
$('.ghl-settings-nav li').removeClass('active');$tab.addClass('active');window.location.hash=tab;loadSettingsTab(tab);closeMobileMenu()});$(window).on('hashchange.ghlSettingsMenu',function(){const hash=window.location.hash.slice(1);if(hash&&hash!==''){const settingsTabs=(typeof ghlCrmSpaConfig!=='undefined'&&ghlCrmSpaConfig.settings)?ghlCrmSpaConfig.settings.tabs:['general','api','rest-api','webhooks','notifications','sync-options','role-tags','conversations','advanced','stats'];if(settingsTabs.includes(hash)){loadSettingsTab(hash);$('.ghl-settings-nav li').removeClass('active');$('.ghl-settings-nav li[data-tab="'+hash+'"]').addClass('active')}}})}
function initMobileMenuToggle(){const $toggleBtn=$('#ghl-menu-toggle');const $nav=$('#ghl-settings-nav');$toggleBtn.off('click.ghlMenuToggle');$(document).off('click.ghlMenuOverlay');$toggleBtn.on('click.ghlMenuToggle',function(e){e.stopPropagation();toggleMobileMenu()});$(document).on('click.ghlMenuOverlay',function(e){if($nav.hasClass('expanded')){const isClickInside=$(e.target).closest('.ghl-settings-nav, #ghl-menu-toggle').length>0;if(!isClickInside){closeMobileMenu()}}});$(document).on('keydown.ghlMenuToggle',function(e){if(e.key==='Escape'&&$nav.hasClass('expanded')){closeMobileMenu()}})}
function toggleMobileMenu(){const $nav=$('#ghl-settings-nav');$nav.toggleClass('expanded');$('body').toggleClass('ghl-menu-open');const isExpanded=$nav.hasClass('expanded');$('#ghl-menu-toggle').attr('aria-expanded',isExpanded)}
function closeMobileMenu(){const $nav=$('#ghl-settings-nav');if($nav.hasClass('expanded')){$nav.removeClass('expanded');$('body').removeClass('ghl-menu-open');$('#ghl-menu-toggle').attr('aria-expanded','false')}}
function loadSettingsTab(tab){const $content=$('.ghl-settings-content');$content.css('opacity','0.5');const ajaxUrl=(typeof ghlCrmSpaConfig!=='undefined')?ghlCrmSpaConfig.ajaxUrl:ajaxurl;const nonce=(typeof ghlCrmSpaConfig!=='undefined')?ghlCrmSpaConfig.nonce:'';$.ajax({url:ajaxUrl,type:'POST',data:{action:'ghl_crm_load_settings_tab',nonce:nonce,tab:tab},success:function(response){if(response.success&&response.data.html){$content.html(response.data.html);if(typeof window.initSettings==='function'){window.initSettings()}
setTimeout(function(){if(typeof tinyMCE!=='undefined'){tinyMCE.EditorManager.execCommand('mceRemoveEditor',!0,'restrictions_denied_message');tinyMCE.EditorManager.execCommand('mceAddEditor',!0,'restrictions_denied_message')}},100);if(typeof window.initUserRegisterTags==='function'){window.initUserRegisterTags()}
if(typeof window.initRestrictionsTagsSelect==='function'){window.initRestrictionsTagsSelect()}
if(typeof window.initRoleTags==='function'){window.initRoleTags()}
if(typeof window.initFamilyAccounts==='function'){window.initFamilyAccounts()}
if(typeof window.ghlSyncPreview.init==='function'){window.ghlSyncPreview.init()}
if(typeof window.initToolsHandlers==='function'){window.initToolsHandlers()}}else{$content.html('<div class="notice notice-error"><p>'+(response.data.message||'Failed to load settings tab.')+'</p></div>')}},error:function(xhr,status,error){$content.html('<div class="notice notice-error"><p>Error loading settings tab. Please try again.</p></div>')},complete:function(){$content.css('opacity','1')}})}
$(document).ready(function(){if($('.ghl-settings-with-sidebar').length){initSettingsMenu()}});function cleanupSettingsMenu(){window.ghlSettingsMenuInitialized=!1;$(document).off('click.ghlSettingsMenu','.ghl-settings-nav li');$(window).off('hashchange.ghlSettingsMenu');$('#ghl-menu-toggle').off('click.ghlMenuToggle');$(document).off('click.ghlMenuOverlay');$(document).off('keydown.ghlMenuToggle');$('body').removeClass('ghl-menu-open')}
window.initSettingsMenu=initSettingsMenu;window.cleanupSettingsMenu=cleanupSettingsMenu})(jQuery)